  "asset"."status",
  "asset"."checksum",
  "asset"."checksumAlgorithm",
  "asset"."duplicateId",
  "asset"."duration",
  "asset"."fileCreatedAt",
  "asset"."fileModifiedAt",
  "asset"."isExternal",
  "asset"."isFavorite",
  "asset"."isOffline",
  "asset"."isEdited",
  "asset"."visibility",
  "asset"."libraryId",
  "asset"."livePhotoVideoId",
  "asset"."localDateTime",
  "asset"."originalFileName",
  "asset"."originalPath",
  "asset"."ownerId",
  "asset"."stackId",
  "asset"."thumbhash",
  "asset"."type",
  "asset"."width",
  "asset"."height"
from
