  and (
    "asset"."isFavorite" = $2
    or exists (
      select
      from
        "asset_face"
      where
        "asset_face"."assetId" = "asset"."id"
        and "asset_face"."deletedAt" is null
        and "asset_face"."isVisible" = $3
        and "asset_face"."personId" = any ($4::uuid[])
    )
  )
order by
  "asset"."fileCreatedAt" desc,
  "asset"."id" desc
limit
  $5

